from dataclasses import dataclass, field
from typing import Dict, List, Optional, Any
from enum import Enum
import time
from collections import defaultdict

class AllocationStrategy(Enum):
    ROUND_ROBIN = "round_robin"
    LEAST_LOADED = "least_loaded"
    BEST_FIT = "best_fit"

@dataclass
class QPUProperties:
    qpu_id: str
    num_qubits: int
    fidelity: float
    cost_per_shot: float

@dataclass
class QPUState:
    properties: QPUProperties
    available: bool = True
    current_load: int = 0
    queue_time: float = 0.0

@dataclass
class JobRequirements:
    job_id: str
    min_qubits: int
    min_fidelity: float
    shots: int

class QPUAllocator:
    def __init__(self, strategy: AllocationStrategy):
        self.strategy = strategy
        self.qpus: Dict[str, QPUState] = {}
        self.allocation_history: List[Dict] = []
        self._rr_index = 0

    def register_qpu(self, state: QPUState):
        self.qpus[state.properties.qpu_id] = state

    def update_qpu(self, qpu_id: str, **kwargs):
        if qpu_id in self.qpus:
            qpu = self.qpus[qpu_id]
            for key, value in kwargs.items():
                if hasattr(qpu, key):
                    setattr(qpu, key, value)

    def allocate(self, requirements: JobRequirements) -> Optional[str]:
        suitable = self._get_suitable_qpus(requirements)
        if not suitable:
            return None

        if self.strategy == AllocationStrategy.ROUND_ROBIN:
            selected = self._round_robin(suitable)
        elif self.strategy == AllocationStrategy.LEAST_LOADED:
            selected = self._least_loaded(suitable)
        else:
            selected = self._best_fit(suitable, requirements)

        self.allocation_history.append({
            "timestamp": time.time(),
            "job_id": requirements.job_id,
            "qpu_id": selected,
            "strategy": self.strategy.value
        })

        self.qpus[selected].current_load += 1
        return selected

    def _get_suitable_qpus(self, requirements: JobRequirements) -> List[QPUState]:
        suitable = []
        for qpu in self.qpus.values():
            if not qpu.available:
                continue
            if qpu.properties.num_qubits < requirements.min_qubits:
                continue
            if qpu.properties.fidelity < requirements.min_fidelity:
                continue
            suitable.append(qpu)
        return suitable

    def _round_robin(self, qpus: List[QPUState]) -> str:
        selected = qpus[self._rr_index % len(qpus)]
        self._rr_index += 1
        return selected.properties.qpu_id

    def _least_loaded(self, qpus: List[QPUState]) -> str:
        return min(qpus, key=lambda q: q.current_load).properties.qpu_id

    def _best_fit(self, qpus: List[QPUState], req: JobRequirements) -> str:
        def score(qpu: QPUState) -> float:
            s = 0.0
            qubit_efficiency = req.min_qubits / qpu.properties.num_qubits
            s += qubit_efficiency * 30
            s += qpu.properties.fidelity * 40
            s -= min(qpu.queue_time / 3600, 10) * 2
            cost = qpu.properties.cost_per_shot * req.shots
            s -= min(cost / 100, 10)
            return s

        return max(qpus, key=score).properties.qpu_id

    def get_statistics(self) -> Dict[str, Any]:
        if not self.allocation_history:
            return {"total": 0}

        usage = defaultdict(int)
        for record in self.allocation_history:
            usage[record["qpu_id"]] += 1

        return {
            "total": len(self.allocation_history),
            "by_qpu": dict(usage),
            "strategy": self.strategy.value
        }

