import heapq
from dataclasses import dataclass
from typing import Dict, List, Optional, Any
from enum import Enum
import time

class PriorityLevel(Enum):
    HIGH = 1
    NORMAL = 2
    LOW = 3

@dataclass
class QueuedJob:
    job_id: str
    priority: PriorityLevel
    submit_time: float
    estimated_duration: float

    def __lt__(self, other):
        if self.priority.value != other.priority.value:
            return self.priority.value < other.priority.value
        return self.submit_time < other.submit_time

class QuantumJobQueue:
    def __init__(self, starvation_threshold: float = 300):
        self.starvation_threshold = starvation_threshold
        self.queues: Dict[PriorityLevel, List[QueuedJob]] = {
            level: [] for level in PriorityLevel
        }
        self.job_index: Dict[str, QueuedJob] = {}
        self.completed_count = 0
        self.total_wait_time = 0.0

    def submit(self, job: QueuedJob) -> bool:
        if job.job_id in self.job_index:
            return False
        heapq.heappush(self.queues[job.priority], job)
        self.job_index[job.job_id] = job
        return True

    def get_next(self) -> Optional[QueuedJob]:
        self._check_starvation()

        for priority in PriorityLevel:
            if self.queues[priority]:
                job = heapq.heappop(self.queues[priority])
                del self.job_index[job.job_id]

                wait = time.time() - job.submit_time
                self.total_wait_time += wait
                self.completed_count += 1

                return job
        return None

    def cancel(self, job_id: str) -> bool:
        if job_id not in self.job_index:
            return False

        job = self.job_index[job_id]
        self.queues[job.priority] = [
            j for j in self.queues[job.priority] if j.job_id != job_id
        ]
        heapq.heapify(self.queues[job.priority])
        del self.job_index[job_id]
        return True

    def _check_starvation(self):
        current = time.time()

        for priority in [PriorityLevel.LOW, PriorityLevel.NORMAL]:
            promoted = []
            remaining = []

            for job in self.queues[priority]:
                if current - job.submit_time > self.starvation_threshold:
                    new_priority = PriorityLevel(max(1, priority.value - 1))
                    job.priority = new_priority
                    promoted.append(job)
                else:
                    remaining.append(job)

            self.queues[priority] = remaining
            heapq.heapify(self.queues[priority])

            for job in promoted:
                self.job_index[job.job_id] = job
                heapq.heappush(self.queues[job.priority], job)

    def get_position(self, job_id: str) -> Optional[int]:
        if job_id not in self.job_index:
            return None

        job = self.job_index[job_id]
        position = 0

        for priority in PriorityLevel:
            if priority.value < job.priority.value:
                position += len(self.queues[priority])
            elif priority == job.priority:
                for q_job in sorted(self.queues[priority]):
                    if q_job.job_id == job_id:
                        break
                    position += 1
                break

        return position

    def get_stats(self) -> Dict[str, Any]:
        lengths = {p.name: len(q) for p, q in self.queues.items()}
        avg_wait = self.total_wait_time / self.completed_count if self.completed_count else 0

        return {
            "queue_lengths": lengths,
            "total_queued": sum(lengths.values()),
            "completed": self.completed_count,
            "avg_wait_time": avg_wait
        }

from dataclasses import dataclass, field
from typing import Dict, List, Any, Optional
from enum import Enum

class PriorityLevel(Enum):
    HIGH = 1
    NORMAL = 2
    LOW = 3
    BATCH = 4

@dataclass
class CostModel:
    backend_id: str
    cost_per_shot: float
    volume_threshold: int
    volume_discount: float
    priority_multipliers: Dict[PriorityLevel, float]

@dataclass
class JobSpec:
    job_id: str
    shots: int
    priority: PriorityLevel

@dataclass
class CostEstimate:
    backend: str
    base_cost: float
    discounts: float
    final_cost: float
    cost_per_shot: float

class CostOptimizer:
    def __init__(self):
        self.cost_models: Dict[str, CostModel] = {}

    def register_backend(self, model: CostModel):
        self.cost_models[model.backend_id] = model

    def estimate_cost(
        self,
        job: JobSpec,
        backend_id: str
    ) -> Optional[CostEstimate]:
        if backend_id not in self.cost_models:
            return None

        model = self.cost_models[backend_id]
        base = model.cost_per_shot * job.shots

        volume_disc = 0.0
        if job.shots >= model.volume_threshold:
            volume_disc = base * model.volume_discount

        priority_mult = model.priority_multipliers.get(job.priority, 1.0)
        final = (base - volume_disc) * priority_mult

        return CostEstimate(
            backend=backend_id,
            base_cost=base,
            discounts=volume_disc + base * (1 - priority_mult),
            final_cost=final,
            cost_per_shot=final / job.shots
        )

    def compare_backends(self, job: JobSpec) -> List[CostEstimate]:
        estimates = []
        for backend_id in self.cost_models:
            est = self.estimate_cost(job, backend_id)
            if est:
                estimates.append(est)
        return sorted(estimates, key=lambda e: e.final_cost)

    def suggest_optimizations(self, job: JobSpec) -> List[Dict[str, Any]]:
        suggestions = []

        for backend_id, model in self.cost_models.items():
            if job.shots < model.volume_threshold:
                additional = model.volume_threshold - job.shots
                savings = job.shots * model.cost_per_shot * model.volume_discount
                suggestions.append({
                    "type": "volume_discount",
                    "backend": backend_id,
                    "action": f"Add {additional} shots to reach threshold",
                    "potential_savings": savings
                })

            if job.priority.value < PriorityLevel.BATCH.value:
                current_mult = model.priority_multipliers.get(job.priority, 1.0)
                batch_mult = model.priority_multipliers.get(PriorityLevel.BATCH, 1.0)
                if batch_mult < current_mult:
                    base = job.shots * model.cost_per_shot
                    savings = base * (current_mult - batch_mult)
                    suggestions.append({
                        "type": "priority_downgrade",
                        "backend": backend_id,
                        "action": "Use BATCH priority for lower cost",
                        "potential_savings": savings
                    })

        return sorted(suggestions, key=lambda s: -s["potential_savings"])

    def plan_batch(
        self,
        jobs: List[JobSpec],
        backend_id: str
    ) -> Dict[str, Any]:
        if backend_id not in self.cost_models:
            return {"error": "Unknown backend"}

        model = self.cost_models[backend_id]

        individual_cost = sum(
            self.estimate_cost(j, backend_id).final_cost
            for j in jobs
        )

        total_shots = sum(j.shots for j in jobs)
        batched_job = JobSpec("batch", total_shots, PriorityLevel.BATCH)
        batched_cost = self.estimate_cost(batched_job, backend_id).final_cost

        return {
            "backend": backend_id,
            "total_jobs": len(jobs),
            "total_shots": total_shots,
            "individual_cost": individual_cost,
            "batched_cost": batched_cost,
            "savings": individual_cost - batched_cost,
            "savings_percent": (individual_cost - batched_cost) / individual_cost * 100
        }

from dataclasses import dataclass
from typing import Dict, List, Optional, Any
from contextlib import contextmanager
import threading
import time

@dataclass
class PooledResource:
    resource_id: str
    backend_id: str
    allocated: bool = False
    allocated_to: Optional[str] = None
    allocated_at: Optional[float] = None

class ResourcePool:
    def __init__(
        self,
        resources_per_backend: int = 5,
        allocation_timeout: float = 3600
    ):
        self.max_resources = resources_per_backend
        self.timeout = allocation_timeout
        self.pools: Dict[str, List[PooledResource]] = {}
        self._lock = threading.Lock()

    def initialize_backend(self, backend_id: str):
        if backend_id in self.pools:
            return

        self.pools[backend_id] = [
            PooledResource(
                resource_id=f"{backend_id}_res_{i}",
                backend_id=backend_id
            )
            for i in range(self.max_resources)
        ]

    def acquire(
        self,
        backend_id: str,
        user_id: str,
        timeout: float = 30
    ) -> Optional[PooledResource]:
        if backend_id not in self.pools:
            self.initialize_backend(backend_id)

        start = time.time()

        while time.time() - start < timeout:
            with self._lock:
                self._cleanup_expired(backend_id)

                for resource in self.pools[backend_id]:
                    if not resource.allocated:
                        resource.allocated = True
                        resource.allocated_to = user_id
                        resource.allocated_at = time.time()
                        return resource

            time.sleep(0.1)

        return None

    def release(self, resource: PooledResource):
        with self._lock:
            resource.allocated = False
            resource.allocated_to = None
            resource.allocated_at = None

    def _cleanup_expired(self, backend_id: str):
        current = time.time()

        for resource in self.pools.get(backend_id, []):
            if resource.allocated and resource.allocated_at:
                if current - resource.allocated_at > self.timeout:
                    resource.allocated = False
                    resource.allocated_to = None
                    resource.allocated_at = None

    @contextmanager
    def resource(self, backend_id: str, user_id: str):
        resource = self.acquire(backend_id, user_id)
        if resource is None:
            raise Exception(f"Could not acquire resource for {backend_id}")

        try:
            yield resource
        finally:
            self.release(resource)

    def reserve(
        self,
        backend_id: str,
        user_id: str,
        count: int,
        duration: float
    ) -> Dict[str, Any]:
        if backend_id not in self.pools:
            self.initialize_backend(backend_id)

        reserved = []

        with self._lock:
            self._cleanup_expired(backend_id)

            available = [
                r for r in self.pools[backend_id]
                if not r.allocated
            ]

            if len(available) < count:
                return {
                    "success": False,
                    "error": f"Only {len(available)} available"
                }

            for resource in available[:count]:
                resource.allocated = True
                resource.allocated_to = user_id
                resource.allocated_at = time.time()
                reserved.append(resource.resource_id)

        return {
            "success": True,
            "reserved": reserved,
            "duration": duration,
            "expires": time.time() + duration
        }

    def get_status(self, backend_id: str) -> Dict[str, Any]:
        if backend_id not in self.pools:
            return {"error": "Backend not initialized"}

        pool = self.pools[backend_id]
        allocated = sum(1 for r in pool if r.allocated)

        return {
            "backend": backend_id,
            "total": len(pool),
            "allocated": allocated,
            "available": len(pool) - allocated,
            "utilization": allocated / len(pool) if pool else 0
        }
